import{_ as i,C as r,o as a,c,au as t,b as n,w as o,a as l,E as d,av as h}from"./chunks/framework.Bpqx6pAq.js";const A=JSON.parse('{"title":"Account service","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/services/account.md","filePath":"api/core/services/account.md"}'),u={name:"api/core/services/account.md"};function m(f,e,p,g,k,v){const s=r("Mermaid");return a(),c("div",null,[e[1]||(e[1]=t('<h1 id="account-service" tabindex="-1">Account service <a class="header-anchor" href="#account-service" aria-label="Permalink to &quot;Account service&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Available as a global service</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This service is powered by <a href="https://github.com/feathersjs-ecosystem/feathers-authentication-management" target="_blank" rel="noreferrer">feathers-authentication-management</a>. It handles user account verification workflows such as email verification, password reset, and identity changes. A custom <code>verifyEmail</code> method is added to trigger email verification programmatically.</p><p>A <code>notifier</code> function is registered to dispatch transactional emails (via the <a href="./mailer.html">mailer service</a>) for each account management action (sign-up, password reset, email change, etc.).</p><h2 id="data-model" tabindex="-1">Data model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data model&quot;">​</a></h2><p>This service associates verification tokens with users to safely reset passwords or change emails. Refer to the <a href="https://github.com/feathersjs-ecosystem/feathers-authentication-management" target="_blank" rel="noreferrer">feathers-authentication-management docs</a> for the full data model.</p><h2 id="hooks" tabindex="-1">Hooks <a class="header-anchor" href="#hooks" aria-label="Permalink to &quot;Hooks&quot;">​</a></h2><p>The following <a href="./../hooks.html">hooks</a> are executed on the <code>account</code> service:</p>',9)),(a(),n(h,null,{default:o(()=>[d(s,{id:"mermaid-29",class:"mermaid",graph:"graph%20TB%0A%20%20before%7Bnone%20before%20all%7D%0A%20%20after%7Bnone%20after%20all%7D%0A%20%20before%20--%20If%20action%20is%20passwordChange%3Cbr%2F%3EresetPwdShort%2FverifySignupSetPassword%20--%3E%20hook1(enforcePasswordPolicy)%0A%20%20hook1%20--%20Password%20validated%20against%20policy%20--%3E%20CREATE%5BCREATE%5D%0A%20%20CREATE%20--%3E%20after%0A%20%20linkStyle%20default%20stroke-width%3A2px%2Cfill%3Anone%2Cstroke%3Ablack%0A%20%20classDef%20hookClass%20fill%3A%23f96%2Cstroke%3A%23333%2Cstroke-width%3A2px%0A%20%20class%20hook1%2Chook2%20hookClass%0A%20%20classDef%20operationClass%20fill%3A%239c6%2Cstroke%3A%23333%2Cstroke-width%3A2px%0A%20%20class%20CREATE%20operationClass%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>To make tests run we need two Gmail accounts:</p><ul><li><code>email-notifications@kalisio.com</code> used as email sender</li><li><code>test@kalisio.com</code> used as user test email</li></ul><blockquote><p>When testing identity change we also use the <code>test@kalisio.xyz</code> address as user test email. However to avoid creating a new account in Google you can simply add an alias for this address to the <code>test@kalisio.com</code> account.</p></blockquote><p>The first email account is used by the <a href="./mailer.html">mailer service</a> to send email notifications. The second email account requires OAuth2 authentication to be able to read emails using the GMail API. The simplest way is by creating a service account for a JWT-based authentication. Interesting issue to make all the configuration work can be found <a href="https://stackoverflow.com/a/29328258" target="_blank" rel="noreferrer">here</a>, notably you have to delegate domain-wide authority to the service account in order to authorize your app to access user data on behalf of users and authorise the client ID of the service account with scopes <code>https://mail.google.com/,https://www.googleapis.com/auth/gmail.readonly</code>.</p><p>Standard OAuth2 with refresh token might also be used as detailed <a href="https://medium.com/@pandeysoni/nodemailer-service-in-node-js-using-smtp-and-xoauth2-7c638a39a37e" target="_blank" rel="noreferrer">here</a>.</p>',6))])}const w=i(u,[["render",m]]);export{A as __pageData,w as default};
